import React from "react";

const Sidebar = () => {
  const menuItems = [
    { id: 1, label: "Dashboard", iconId: "icon-dashboard", active: true },
    { id: 2, label: "Vital Task", iconId: "icon-vital" }, // змініть ID на ваші реальні з файлу
    { id: 3, label: "My Task", iconId: "icon-task" },
    { id: 4, label: "Task Categories", iconId: "icon-categories" },
    { id: 5, label: "Settings", iconId: "icon-settings" },
    { id: 6, label: "Help", iconId: "icon-help" },
  ];

  return (
    <aside className="sidebar">
      <div className="sidebar-profile">
        <div className="profile-avatar">
          <img src="images/profile_image.jpg" alt="Sundar Gurung" />
        </div>
        <h3 className="profile-name">Sundar Gurung</h3>
        <p className="profile-email">sundargurung360@gmail.com</p>
      </div>

      <nav className="sidebar-nav">
        {menuItems.map((item) => (
          <div
            key={item.id}
            className={`nav-item ${item.active ? "active" : ""}`}
          >
            <img
              src={`images/icons/${item.icon}`}
              alt={item.label}
              className="nav-icon"
            />
            <span>{item.label}</span>
          </div>
        ))}
      </nav>

      <div className="sidebar-logout">
        <div className="nav-item">
          <img
            src="images/icons/logout.svg"
            alt="logout"
            className="nav-icon"
          />
          <span>Logout</span>
        </div>
      </div>
    </aside>
  );
};

export default Sidebar;
